// ============================================================
// ⚙️ KONFIGURATION – NocoDB API Token hier eintragen:
// ============================================================
const NOCODB_TOKEN = 'DEIN_NOCODB_API_TOKEN_HIER';
// Token findest du in NocoDB → Team & Auth → API Token
// ============================================================

return [{
  json: {
    nocodbBase: 'https://nocodb.f3-events.de/api/v2',
    eventsTable: 'mo0qnkmte1sl1mj',
    token: NOCODB_TOKEN,
    joyclubUrl: 'https://www.joyclub.de/party/13140845.f3.html',
    telegramGroup: '-1003592524930'
  }
}];

const html = $input.first().json.data || $input.first().json.body || '';

if (!html || html.length < 500) {
  throw new Error('Joyclub Profil konnte nicht geladen werden');
}

// Alle Event-Links aus dem Profil extrahieren
const pattern = /href="(\/event\/\d+\.[^"]+\.html)"/g;
const urls = new Set();
let m;
while ((m = pattern.exec(html)) !== null) {
  urls.add('https://www.joyclub.de' + m[1]);
}

if (urls.size === 0) {
  throw new Error('Keine Event-Links auf Joyclub-Profilseite gefunden');
}

console.log(`✅ ${urls.size} Event-Links gefunden`);

return [...urls].map(url => ({ json: { url } }));

const html = $input.first().json.data || $input.first().json.body || '';
const url = $('🔄 Event-Loop').first().json.url;

if (!html || html.length < 200) {
  console.log(`⚠️ Leere Antwort für: ${url}`);
  return [{ json: { _skip: true, EventLink: url } }];
}

// ===== TITLE =====
let title = '';
const titleTag = html.match(/<title>([^<]+)/i);
if (titleTag) {
  title = titleTag[1].split('|')[0].trim();
  // Emojis entfernen
  title = title.replace(/[\u{1F300}-\u{1FFFF}\u{2600}-\u{27FF}\u{2B00}-\u{2BFF}]/gu, '').trim();
  title = title.replace(/^[^a-zA-ZäöüÄÖÜ]+/, '').trim(); // führende Sonderzeichen
}
// Fallback h1
if (!title) {
  const h1 = html.match(/<h1[^>]*>([^<]+)/i);
  if (h1) title = h1[1].replace(/[\u{1F300}-\u{1FFFF}]/gu, '').trim();
}

// ===== DATUM =====
const monthMap = {
  'Januar':'01','Februar':'02','März':'03','April':'04',
  'Mai':'05','Juni':'06','Juli':'07','August':'08',
  'September':'09','Oktober':'10','November':'11','Dezember':'12'
};
const dayMap = {
  'Montag':'Mo','Dienstag':'Di','Mittwoch':'Mi','Donnerstag':'Do',
  'Freitag':'Fr','Samstag':'Sa','Sonntag':'So'
};

let isoDate = '';
let datumDisplay = '';
let wochentag = '';

const dateRx = /(Montag|Dienstag|Mittwoch|Donnerstag|Freitag|Samstag|Sonntag),?\s+(\d{1,2})\. +(Januar|Februar|März|April|Mai|Juni|Juli|August|September|Oktober|November|Dezember) +(\d{4})/;
const dateM = html.match(dateRx);
if (dateM) {
  const day = dateM[2].padStart(2, '0');
  const mon = monthMap[dateM[3]];
  const yr = dateM[4];
  isoDate = `${yr}-${mon}-${day}`;
  datumDisplay = `${day}.${mon}.${yr}`;
  wochentag = dayMap[dateM[1]] || '';
}

// Mehrtägiges Event (z.B. Mallorca)
const endRx = /[–-]\s*(\d{1,2})\. +(Januar|Februar|März|April|Mai|Juni|Juli|August|September|Oktober|November|Dezember)? *(\d{4})/;
const endM = html.match(endRx);
if (endM && datumDisplay) {
  const endDay = endM[1].padStart(2, '0');
  const endMon = endM[2] ? monthMap[endM[2]] : datumDisplay.slice(3, 5);
  const endYr = endM[3] || datumDisplay.slice(6, 10);
  const endIso = `${endYr}-${endMon}-${endDay}`;
  if (endIso > isoDate) {
    isoDate = endIso; // Archivierung erst nach End-Datum
    datumDisplay = `${datumDisplay.slice(0,2)}.\u2013${endDay}.${endMon}.${endYr}`;
  }
}

// ===== STADT =====
let city = '';
// PLZ + Stadtname
const cityRx = /\b\d{4,5}\s+([A-ZÄÖÜ][a-zA-ZäöüÄÖÜ\s\-]{2,30}?)(?=[<,\n])/;
const cityM = html.match(cityRx);
if (cityM) {
  city = cityM[1].trim();
} else {
  // Fallback: aus URL-Slug
  const slug = url.split('/').pop().replace('.html','');
  const parts = slug.split('_');
  if (parts.length >= 2) {
    city = parts[parts.length - 1].replace(/\b\w/g, c => c.toUpperCase());
  }
}

// ===== STATUS =====
const isCancelled = /wurde\s+abgesagt|veranstaltung.*?abgesagt/i.test(html);
const status = isCancelled ? 'inaktiv' : 'aktiv';

// ===== BESCHREIBUNG =====
let beschreibung = '';
const blocks = [];
const pRx = /<p[^>]*>([\s\S]{80,}?)<\/p>/gi;
let pM;
while ((pM = pRx.exec(html)) !== null && blocks.length < 3) {
  const text = pM[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
  if (text.length > 60 && !/cookie|javascript|anmelden/i.test(text)) {
    blocks.push(text);
  }
}
beschreibung = blocks.slice(0, 2).join('\n\n').slice(0, 500);

// ===== ANMELDESTAND =====
let anmeldestand = '';
const anmM = html.match(/(\d+)\s+(Angemeldete|Teilnehmer)/i);
if (anmM) anmeldestand = `${anmM[1]} Angemeldete`;

// ===== DISPLAY DATUM (mit Stadt) =====
const displayDatum = city && datumDisplay ? `${datumDisplay} \u00b7 ${city}` : datumDisplay;

return [{
  json: {
    EventName: title || 'F³ Event',
    EventLink: url,
    EventDatum: displayDatum,
    _isoDate: isoDate,
    'Event-Beschreibung': beschreibung,
    Wochentag: wochentag,
    Anmeldestand: anmeldestand,
    Status: status
  }
}];

const searchResult = $input.first().json;
const eventData = $('📄 Event parsen').first().json;

// Skip-Flag (Parsing fehlgeschlagen)
if (eventData._skip) {
  return [{ json: { _skip: true, existingId: null, ...eventData } }];
}

// Existiert der Eintrag bereits in NocoDB?
const existingRecord = searchResult.list && searchResult.list.length > 0 ? searchResult.list[0] : null;
const existingId = existingRecord ? existingRecord.Id : null;

console.log(existingId 
  ? `🔄 Update: ${eventData.EventName} (Id: ${existingId})`
  : `➕ Neu: ${eventData.EventName}`);

return [{
  json: {
    ...eventData,
    existingId: existingId
  }
}];
